import React, { useState } from "react";
import Marquee from "react-fast-marquee";
import img1 from "./images/01.png";
import img2 from "./images/02.png";
import img3 from "./images/03.png";
import img4 from "./images/04.png";
import img5 from "./images/04.png";
import "./App.css";

const images = [
  { src:img1 , text: "Text for image 1" }
];

function MarqueeExample() {
  const [isHovered, setIsHovered] = useState(false);

  function handleClick(imageIndex) {
    window.location.href = `page${imageIndex + 1}.html`;
  }

  return (
    <div className="marquee-container">
      <Marquee
        gradient={false}
        speed={40}
        direction="left"
        pauseOnHover={true}
      >
        {images.map((image, index) => (
          <div
            key={index}
            className="marquee-item"
            // onClick={() => handleClick(index)}
          >
            <div className="marquee-item-box">
              <img src={image.src} alt="example" />
              {/* <span>
                <p>{image.text}</p>
              </span> */}
            </div>
          </div>
        ))}
      </Marquee>
    </div>
  );
}

export default MarqueeExample;
